CREATE TABLE IF NOT EXISTS drugs (id INTEGER PRIMARY KEY AUTOINCREMENT, name VARCHAR(255) NOT NULL, generic_name VARCHAR(255) NOT NULL, dosage_form VARCHAR(100) NOT NULL, strength VARCHAR(100) NOT NULL, category VARCHAR(100), unit_of_measure VARCHAR(50), reorder_level INTEGER DEFAULT 50, max_stock INTEGER DEFAULT 1000, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS drug_batches (id INTEGER PRIMARY KEY AUTOINCREMENT, drug_id INTEGER NOT NULL, batch_number VARCHAR(100) NOT NULL, supplier VARCHAR(255), quantity_received INTEGER NOT NULL, quantity_remaining INTEGER NOT NULL, expiry_date DATE NOT NULL, purchase_price DECIMAL(10,2), selling_price DECIMAL(10,2), date_received DATE DEFAULT CURRENT_DATE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (drug_id) REFERENCES drugs(id));
CREATE TABLE IF NOT EXISTS inventory (id INTEGER PRIMARY KEY AUTOINCREMENT, drug_id INTEGER NOT NULL UNIQUE, total_quantity INTEGER DEFAULT 0, reserved_quantity INTEGER DEFAULT 0, available_quantity INTEGER DEFAULT 0, last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (drug_id) REFERENCES drugs(id));
CREATE TABLE IF NOT EXISTS prescription_items (id INTEGER PRIMARY KEY AUTOINCREMENT, prescription_id INTEGER NOT NULL, drug_id INTEGER NOT NULL, batch_id INTEGER, quantity_prescribed INTEGER NOT NULL, quantity_dispensed INTEGER DEFAULT 0, dosage VARCHAR(255), duration VARCHAR(100), instructions TEXT, status VARCHAR(50) DEFAULT 'pending', dispensed_by INTEGER, dispensed_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (drug_id) REFERENCES drugs(id), FOREIGN KEY (batch_id) REFERENCES drug_batches(id));
CREATE TABLE IF NOT EXISTS dispensations (id INTEGER PRIMARY KEY AUTOINCREMENT, prescription_id INTEGER NOT NULL, patient_id INTEGER NOT NULL, dispensed_by INTEGER NOT NULL, dispensed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, total_items INTEGER, status VARCHAR(50) DEFAULT 'completed', notes TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS dispensation_items (id INTEGER PRIMARY KEY AUTOINCREMENT, dispensation_id INTEGER NOT NULL, drug_id INTEGER NOT NULL, batch_id INTEGER NOT NULL, quantity_dispensed INTEGER NOT NULL, unit_price DECIMAL(10,2), total_price DECIMAL(10,2), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (dispensation_id) REFERENCES dispensations(id), FOREIGN KEY (drug_id) REFERENCES drugs(id), FOREIGN KEY (batch_id) REFERENCES drug_batches(id));
CREATE TABLE IF NOT EXISTS stock_movements (id INTEGER PRIMARY KEY AUTOINCREMENT, drug_id INTEGER NOT NULL, batch_id INTEGER, movement_type VARCHAR(50), quantity INTEGER NOT NULL, reference_type VARCHAR(100), reference_id INTEGER, notes TEXT, created_by INTEGER, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (drug_id) REFERENCES drugs(id));
CREATE INDEX idx_drugs_name ON drugs(name); CREATE INDEX idx_batches_expiry ON drug_batches(expiry_date); CREATE INDEX idx_batches_drug ON drug_batches(drug_id); CREATE INDEX idx_prescription_items_status ON prescription_items(status); CREATE INDEX idx_dispensations_patient ON dispensations(patient_id); CREATE INDEX idx_stock_movements_drug ON stock_movements(drug_id);
