INSERT INTO inventory (drug_id, total_quantity, available_quantity) SELECT id, 0, 0 FROM drugs;
UPDATE inventory SET total_quantity = (SELECT COALESCE(SUM(quantity_remaining), 0) FROM drug_batches WHERE drug_id = inventory.drug_id), available_quantity = (SELECT COALESCE(SUM(quantity_remaining), 0) FROM drug_batches WHERE drug_id = inventory.drug_id);
